253	// CapabilitiesViaService returns HarnessCapabilities for the named harness by
254	// querying the service's ListHarnesses and (best-effort) the harness registry.
255	// It is the production replacement for Runner.Capabilities.
256	func CapabilitiesViaService(ctx context.Context, workDir, harnessName string) (*HarnessCapabilities, error) {
257		if ctx == nil {
258			ctx = context.Background()
259		}
260		svc, err := NewServiceFromWorkDir(workDir)
261		if err != nil {
262			return nil, fmt.Errorf("agent: build service: %w", err)
263		}
264		infos, err := svc.ListHarnesses(ctx)
265		if err != nil {
266			return nil, fmt.Errorf("agent: list harnesses: %w", err)
267		}
268		var info *agentlib.HarnessInfo
269		for i := range infos {
270			if infos[i].Name == harnessName {
271				info = &infos[i]
272				break
273			}
274		}
275		if info == nil {
276			return nil, fmt.Errorf("agent: unknown harness: %s", harnessName)
277		}
278	
279		// Pull binary and reasoning-level metadata from the local registry — the
280		// service does not expose these directly today.
281		registry := newHarnessRegistry()
282		harness, _ := registry.Get(harnessName)
283	
284		caps := &HarnessCapabilities{
285			Harness:             info.Name,
286			Available:           info.Available,
287			Binary:              harness.Binary,
288			Path:                info.Path,
289			Surface:             harness.Surface,
290			CostClass:           info.CostClass,
291			IsLocal:             info.IsLocal,
292			ExactPinSupport:     info.ExactPinSupport,
293			SupportsEffort:      len(info.SupportedReasoning) > 0 || harness.EffortFlag != "",
294			SupportsPermissions: len(info.SupportedPermissions) > 0 || len(harness.PermissionArgs) > 0,
295		}
296		if len(info.SupportedReasoning) > 0 {
297			caps.ReasoningLevels = append([]string{}, info.SupportedReasoning...)
298		} else if len(harness.ReasoningLevels) > 0 {
299			caps.ReasoningLevels = append([]string{}, harness.ReasoningLevels...)
300		}
301	
302		if harness.DefaultModel != "" {
303			caps.Model = harness.DefaultModel
304			caps.Models = []string{harness.DefaultModel}
305		}
306	
307		// Profile mappings come from the local model catalog because the service
308		// does not surface a per-tier resolution endpoint today.
309		if harness.Surface != "" {
310			cat := BuiltinCatalog
311			for _, profile := range []string{"cheap", "fast", "smart"} {
312				if m, ok := cat.Resolve(profile, harness.Surface); ok {
313					if caps.ProfileMappings == nil {
314						caps.ProfileMappings = make(map[string]string)
315					}
316					caps.ProfileMappings[profile] = m
317				}
318			}
319		}
320		return caps, nil
321	}
