126	// RunCompareWith dispatches the same prompt to multiple harnesses, executing
127	// each arm via run, and returns a ComparisonRecord. Production callers should
128	// use RunCompareWithConfigViaService; tests may pass an arbitrary RunFunc.
129	func RunCompareWith(run RunFunc, runtime CompareRuntime, resolvePrompt func(AgentRunRuntime) (string, error), cleanupSandbox func(repoDir, compareID string)) (*ComparisonRecord, error) {
130		if len(runtime.Harnesses) == 0 {
131			return nil, fmt.Errorf("agent: compare requires at least one harness")
132		}
133		if resolvePrompt == nil {
134			resolvePrompt = defaultResolvePromptForCompare
135		}
136	
137		prompt, err := resolvePrompt(runtime.AgentRunRuntime)
138		if err != nil {
139			return nil, err
140		}
141	
142		id := genCompareID()
143		record := &ComparisonRecord{
144			ID:        id,
145			Timestamp: time.Now().UTC(),
146			Prompt:    prompt,
147			Arms:      make([]ComparisonArm, len(runtime.Harnesses)),
148		}
149	
150		baseDir := runtime.WorkDir
151		if baseDir == "" {
152			baseDir, _ = os.Getwd()
153		}
154	
155		worktrees := make([]string, len(runtime.Harnesses))
156		if runtime.Sandbox {
157			for i, harness := range runtime.Harnesses {
158				label := harness
159				if l, ok := runtime.ArmLabels[i]; ok {
160					label = l
161				}
162				wt, err := createCompareWorktree(baseDir, id, label)
163				if err != nil {
164					record.Arms[i] = ComparisonArm{
165						Harness:  label,
166						ExitCode: 1,
167						Error:    fmt.Sprintf("worktree: %s", err),
168					}
169					continue
170				}
171				worktrees[i] = wt
172			}
173		}
174	
175		var wg sync.WaitGroup
176		for i, harness := range runtime.Harnesses {
177			if runtime.Sandbox && worktrees[i] == "" && record.Arms[i].Error != "" {
178				continue
179			}
180			wg.Add(1)
181			go func(idx int, harnessName string) {
182				defer wg.Done()
183				record.Arms[idx] = runCompareArmWith(run, runtime, idx, harnessName, baseDir, prompt, worktrees[idx])
184			}(i, harness)
185		}
186		wg.Wait()
187	
188		if runtime.Sandbox && !runtime.KeepSandbox {
189			if cleanupSandbox != nil {
190				cleanupSandbox(baseDir, id)
191			} else {
192				cleanupCompareWorktrees(baseDir, id)
193			}
194		}
195	
196		return record, nil
197	}
