215	func runCompareArmWith(run RunFunc, runtime CompareRuntime, armIdx int, harnessName, baseDir, prompt, worktreePath string) ComparisonArm {
216		label := harnessName
217		if l, ok := runtime.ArmLabels[armIdx]; ok {
218			label = l
219		}
220		arm := ComparisonArm{Harness: label}
221	
222		workDir := baseDir
223		if worktreePath != "" {
224			workDir = worktreePath
