268	func createCompareWorktree(workDir, compareID, harnessName string) (string, error) {
269		gitRoot, err := resolveGitRoot(workDir)
270		if err != nil {
271			return "", fmt.Errorf("resolving git root: %w", err)
272		}
273		wtDir := filepath.Join(gitRoot, ".worktrees", fmt.Sprintf("%s-%s", compareID, harnessName))
274		cmd := internalgit.Command(context.Background(), gitRoot, "worktree", "add", "--detach", wtDir, "HEAD")
275		if out, err := cmd.CombinedOutput(); err != nil {
276			return "", fmt.Errorf("git worktree add: %s\n%s", err, string(out))
277		}
278		return wtDir, nil
279	}
