281	func resolveGitRoot(dir string) (string, error) {
282		cmd := internalgit.Command(context.Background(), dir, "rev-parse", "--show-toplevel")
283		out, err := cmd.Output()
284		if err != nil {
285			return "", fmt.Errorf("not a git repository: %s", dir)
286		}
287		return strings.TrimSpace(string(out)), nil
288	}
