290	func captureGitDiff(worktreePath string) string {
291		cmd := internalgit.Command(context.Background(), worktreePath, "diff", "HEAD")
292		out, err := cmd.Output()
293		if err != nil {
294			return ""
295		}
296		diff := string(out)
297	
298		cmd3 := internalgit.Command(context.Background(), worktreePath, "ls-files", "--others", "--exclude-standard")
299		untrackedOut, _ := cmd3.Output()
300		untracked := strings.TrimSpace(string(untrackedOut))
301		if untracked != "" {
302			for _, f := range strings.Split(untracked, "\n") {
303				f = strings.TrimSpace(f)
304				if f == "" {
305					continue
306				}
307				content, err := os.ReadFile(filepath.Join(worktreePath, f))
308				if err != nil {
309					continue
310				}
311				diff += fmt.Sprintf("\n--- /dev/null\n+++ b/%s\n@@ -0,0 +1 @@\n", f)
312				for _, line := range strings.Split(string(content), "\n") {
313					if line != "" || len(content) > 0 {
314						diff += "+" + line + "\n"
315					}
316				}
317			}
318		}
319		return strings.TrimSpace(diff)
320	}
