329	// cleanupCompareWorktrees removes the worktrees created for a compare run.
330	// Free function; both RunCompareViaService and RunCompareWithAgent route through
331	// this helper.
332	func cleanupCompareWorktrees(repoDir, compareID string) {
333		if root, err := resolveGitRoot(repoDir); err == nil {
334			repoDir = root
335		}
336		wtBase := filepath.Join(repoDir, ".worktrees")
337		entries, err := os.ReadDir(wtBase)
338		if err != nil {
339			return
340		}
341		for _, e := range entries {
342			if e.IsDir() && strings.HasPrefix(e.Name(), compareID) {
343				wtPath := filepath.Join(wtBase, e.Name())
344				cmd := internalgit.Command(context.Background(), repoDir, "worktree", "remove", "--force", wtPath)
345				_ = cmd.Run()
346			}
347		}
348		cmd := internalgit.Command(context.Background(), repoDir, "worktree", "prune")
349		_ = cmd.Run()
350	}
