403			return nil, fmt.Errorf("agent: quorum requires at least one harness")
404		}
405	
406		threshold := effectiveThreshold(runtime.Strategy, runtime.Threshold, len(runtime.Harnesses))
407		if threshold < 1 || threshold > len(runtime.Harnesses) {
408			return nil, fmt.Errorf("agent: invalid quorum threshold %d for %d harnesses", threshold, len(runtime.Harnesses))
409		}
410	
411		results := make([]*Result, len(runtime.Harnesses))
412		var wg sync.WaitGroup
413		var mu sync.Mutex
414		var firstErr error
415	
416		for i, name := range runtime.Harnesses {
417			wg.Add(1)
418			go func(idx int, harness string) {
419				defer wg.Done()
420				armRuntime := runtime.AgentRunRuntime
421				armRuntime.HarnessOverride = harness
422				result, err := run(armRuntime)
423				mu.Lock()
424				if err != nil && firstErr == nil {
425					firstErr = err
426				}
427				results[idx] = result
428				mu.Unlock()
429			}(i, name)
430		}
431		wg.Wait()
432	
433		return results, firstErr
434	}
