436	// QuorumMet returns true if enough results succeeded.
437	func QuorumMet(strategy string, threshold int, results []*Result) bool {
438		total := len(results)
439		eff := effectiveThreshold(strategy, threshold, total)
440		successes := 0
441		for _, r := range results {
442			if r != nil && r.ExitCode == 0 {
443				successes++
444			}
445		}
446		return successes >= eff
447	}
448	
449	func effectiveThreshold(strategy string, threshold, total int) int {
450		switch strategy {
451		case "any":
452			return 1
453		case "majority":
454			return (total / 2) + 1
455		case "unanimous":
456			return total
457		default:
458			if threshold > 0 {
459				return threshold
460			}
461			return 1
462		}
463	}
