465	// CondenseOutput filters raw agent output to keep only progress-relevant lines.
466	// The canonical implementation lives in agent/internal/comparison.CondenseOutput.
467	func CondenseOutput(input, namespacePrefix string) string {
468		var kept []string
469		skippingTokens := false
470		skippingDiff := false
471		blankRun := 0
472		lastWasKept := false
473		keepNextResult := false
474	
475		lines := strings.Split(input, "\n")
476		if len(lines) > 0 && lines[len(lines)-1] == "" {
477			lines = lines[:len(lines)-1]
478		}
479	
480		for _, line := range lines {
481			if strings.HasPrefix(line, "Commands run:") {
482				continue
483			}
484			if line == "tokens used" {
485				skippingTokens = true
486				continue
487			}
488			if skippingTokens {
489				skippingTokens = false
490				continue
491			}
492			if condenseIsDiffHeader(line) {
493				skippingDiff = true
494				continue
495			}
496			if skippingDiff {
497				if condenseIsDiffHeader(line) {
498					continue
499				}
500				if len(line) > 0 && (line[0] == '+' || line[0] == '-' || line[0] == ' ') {
501					continue
502				}
503				skippingDiff = false
504			}
505			if line == "" {
506				blankRun++
507				continue
508			}
509			keep := false
510			if keepNextResult {
511				keep = true
512				keepNextResult = false
513			}
514			if namespacePrefix != "" && strings.HasPrefix(line, namespacePrefix) {
515				keep = true
516			}
517			if strings.HasPrefix(line, "$ ") {
518				keep = true
519				keepNextResult = true
520			}
521			for _, kw := range []string{"error", "Error", "ERROR", "warning", "Warning", "WARN", "FAIL", "fail", "panic"} {
522				if strings.Contains(line, kw) {
523					keep = true
524					break
525				}
526			}
527			for _, kw := range []string{"hx-", "helix-", "FEAT-", "US-", "COMPLETE", "BLOCKED", "CLOSED", "closed", "commit "} {
528				if strings.Contains(line, kw) {
529					keep = true
530					break
531				}
532			}
533			if len(line) > 0 && condenseIsAlphaNumUnderscore(rune(line[0])) && strings.Contains(line, ":") {
534				keep = true
535			}
536			if strings.HasPrefix(line, "#") || strings.HasPrefix(line, "|") || strings.HasPrefix(line, " |") || strings.HasPrefix(line, "**") {
537				keep = true
538			}
539			if strings.HasPrefix(line, "Phase") || strings.HasPrefix(line, "Step") || strings.HasPrefix(line, "---") {
540				keep = true
541			}
542			if keep {
543				if lastWasKept && blankRun > 0 {
544					kept = append(kept, "")
545				}
546				blankRun = 0
547				lastWasKept = true
548				kept = append(kept, line)
549			}
550		}
551	
552		if len(kept) == 0 {
553			return ""
554		}
555		result := strings.Join(kept, "\n")
556		return condenseTrimBlankLines(result)
557	}
558	
559	func condenseIsDiffHeader(line string) bool {
560		return strings.HasPrefix(line, "diff --git ") ||
561			strings.HasPrefix(line, "index ") ||
562			strings.HasPrefix(line, "--- a/") ||
563			strings.HasPrefix(line, "+++ b/") ||
564			strings.HasPrefix(line, "@@ ")
565	}
566	
567	func condenseIsAlphaNumUnderscore(r rune) bool {
568		return (r >= 'A' && r <= 'Z') || (r >= '0' && r <= '9') || r == '_'
569	}
570	
571	func condenseTrimBlankLines(s string) string {
572		lines := strings.Split(s, "\n")
573		start := 0
574		for start < len(lines) && strings.TrimSpace(lines[start]) == "" {
575			start++
576		}
577		end := len(lines)
578		for end > start && strings.TrimSpace(lines[end-1]) == "" {
579			end--
580		}
581		return strings.Join(lines[start:end], "\n")
582	}
