598	// RunBenchmarkWith executes all prompts in a suite against all arms via the
599	// runCompare closure. Production callers should use
600	// RunBenchmarkWithConfigViaService.
601	func RunBenchmarkWith(runCompare func(CompareRuntime) (*ComparisonRecord, error), suite *BenchmarkSuite) (*BenchmarkResult, error) {
602		result := &BenchmarkResult{
603			Suite:     suite.Name,
604			Version:   suite.Version,
605			Timestamp: time.Now().UTC(),
606			Arms:      suite.Arms,
607		}
608	
609		if suite.Timeout != "" {
610			if _, err := time.ParseDuration(suite.Timeout); err != nil {
611				return nil, fmt.Errorf("invalid timeout %q: %w", suite.Timeout, err)
612			}
613		}
614	
615		for _, prompt := range suite.Prompts {
616			promptText := prompt.Prompt
617			if promptText == "" && prompt.PromptFile != "" {
618				data, err := readPromptFileBounded(prompt.PromptFile)
619				if err != nil {
620					return nil, fmt.Errorf("reading prompt file %s: %w", prompt.PromptFile, err)
621				}
622				promptText = string(data)
623			}
624	
625			runtime := BenchmarkArmsToCompare(suite.Arms, AgentRunRuntime{Prompt: promptText})
626			runtime.Sandbox = suite.Sandbox
627			runtime.PostRun = suite.PostRun
628	
629			record, err := runCompare(runtime)
630			if err != nil {
631				return nil, fmt.Errorf("prompt %s: %w", prompt.ID, err)
632			}
633	
634			result.Comparisons = append(result.Comparisons, *record)
635		}
636	
637		result.Summary = benchSummarize(result)
638		return result, nil
639	}
