642	// benchmarks. It threads a sealed ResolvedConfig through each per-prompt
643	// comparison via RunCompareWithConfigViaService.
644	func RunBenchmarkWithConfigViaService(ctx context.Context, workDir string, rcfg config.ResolvedConfig, suite *BenchmarkSuite) (*BenchmarkResult, error) {
645		return RunBenchmarkWith(func(runtime CompareRuntime) (*ComparisonRecord, error) {
646			return RunCompareWithConfigViaService(ctx, workDir, rcfg, runtime)
647		}, suite)
648	}
