650	func benchSummarize(result *BenchmarkResult) BenchmarkSummary {
651		summary := BenchmarkSummary{
652			TotalPrompts: len(result.Comparisons),
653		}
654		armStats := make(map[string]*BenchmarkArmSummary)
655		armOrder := make([]string, len(result.Arms))
656		for i, arm := range result.Arms {
657			label := arm.Label
658			armOrder[i] = label
659			armStats[label] = &BenchmarkArmSummary{Label: label}
660		}
661		for _, cmp := range result.Comparisons {
662			for _, arm := range cmp.Arms {
663				stats, ok := armStats[arm.Harness]
664				if !ok {
665					continue
666				}
667				if arm.ExitCode == 0 {
668					stats.Completed++
669				} else {
670					stats.Failed++
671				}
672				stats.TotalTokens += arm.Tokens
673				stats.TotalCostUSD += arm.CostUSD
674				stats.AvgDurationMS += arm.DurationMS
675			}
676		}
677		for _, label := range armOrder {
678			stats := armStats[label]
679			total := stats.Completed + stats.Failed
680			if total > 0 {
681				stats.AvgDurationMS = stats.AvgDurationMS / total
682			}
683			summary.Arms = append(summary.Arms, *stats)
684		}
685		return summary
686	}
